import sys

n,m=map(int,input().split())

def dfs(x,y,color):
    if y==m:
        y=0
        x+=1
    if x==n:
        print('\n'.join(map(''.join,board)))
        sys.exit()
    for i in range(ord('A'),ord('A')+m):
        if color=='A' and x>0 and board[x-1][y]==chr(i):
            continue
        if color=='B' and y>0 and board[x][y-1]==chr(i):
            continue
        board[x][y]=chr(i)
        dfs(x,y+1,chr(i))
        board[x][y]='.'

board=[['.']*m for _ in range(n)]
dfs(0,0,'A')
